import React, { useEffect, useState, useContext } from 'react';
import { AuthContext } from '../contexts/AuthContext';

const API_URL = 'http://localhost:3001/api';

export default function Lobby({ onJoin }) {
  const { token, user, logout } = useContext(AuthContext);
  const [rooms, setRooms] = useState([]);
  const [message, setMessage] = useState('');
  const [msgType, setMsgType] = useState('');
  const [newRoom, setNewRoom] = useState({ roomId: '', maxPlayers: 4, entryFee: 10, prizeDistribution: 'top4' });
  const [loading, setLoading] = useState(false);

  const fetchRooms = async () => {
    if (!token) return;
    try {
      const res = await fetch(`${API_URL}/rooms`, { headers: { Authorization: `Bearer ${token}` } });
      if (!res.ok) throw new Error('Unable to load rooms');
      setRooms(await res.json());
      setMessage('');
    } catch (e) {
      setMessage(e.message || 'Unable to load rooms');
      setMsgType('error');
    }
  };

  useEffect(() => {
    fetchRooms();
    const interval = setInterval(fetchRooms, 5000); // Refresh every 5 seconds
    return () => clearInterval(interval);
  }, [token]);

  const joinRoom = async (room) => {
    try {
      console.log("ROOM DATA:", room); // Debug log
      console.log("Sending roomId:", room._id); // Verify correct id is being sent

      const res = await fetch(`${API_URL}/rooms/join`, {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ roomId: room._id })
      });
      if (!res.ok) throw new Error('Join failed');

      // Redirect to the room page after successful join
      window.location.href = `/room/${room._id}`;

    } catch (err) {
      console.error("Join failed:", err.message);
      setMessage(err.message || 'Join failed');
      setMsgType('error');
    }
  };

const createRoom = async (e) => {
    e.preventDefault();
    if (!newRoom.roomId.trim()) {
      setMessage('Room ID is required');
      setMsgType('error');
      return;
    }

    try {
      setLoading(true);
      const payload = {
        roomId: newRoom.roomId.trim(),
        maxPlayers: Number(newRoom.maxPlayers),
        entryFee: Number(newRoom.entryFee),
        prizeDistribution: newRoom.prizeDistribution
      };
      const res = await fetch(`${API_URL}/rooms/create`, {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(payload)
      });
      if (!res.ok) throw new Error('Could not create room');
      setNewRoom({ roomId: '', maxPlayers: 4, entryFee: 10, prizeDistribution: 'top4' });
      setMessage('✓ Room created successfully');
      setMsgType('success');
      await fetchRooms();
    } catch (e) {
      setMessage(e.message || 'Could not create room');
      setMsgType('error');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen p-4 lg:p-10">
      <div className="max-w-7xl mx-auto">
        <header className="flex flex-wrap items-center justify-between gap-4 mb-8">
          <div>
            <h1 className="text-5xl font-black tracking-tight mb-1">Chess Arena</h1>
            <p className="text-slate-300">Welcome back, <span className="text-cyan-300 font-semibold">{user?.username}</span></p>
          </div>
          <div className="flex items-center gap-3">
            <button onClick={logout} className="btn-secondary">Logout</button>
            <span className="status-pill bg-lime-500/20 text-lime-200 border border-lime-400">Online</span>
          </div>
        </header>

        {/* Message Alerts */}
        {message && (
          <div className={`mb-6 p-4 rounded-lg border ${
            msgType === 'success' 
              ? 'bg-green-900/30 border-green-700 text-green-400' 
              : 'bg-red-900/30 border-red-700 text-red-400'
          }`}>
            {message}
          </div>
        )}

        <div className="grid lg:grid-cols-3 gap-8">
          {/* Create Room + Room List */}
          <div className="lg:col-span-1">
            <div className="card sticky top-8">
              <h3 className="text-xl font-bold mb-6 flex items-center">
                <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-cyan-500 to-blue-500 flex items-center justify-center mr-3">
                  <svg className="w-5 h-5 text-white" fill="currentColor" viewBox="0 0 20 20">
                    <path d="M10.5 1.5H5.75A2.25 2.25 0 003.5 3.75v12.5A2.25 2.25 0 005.75 18.5h8.5a2.25 2.25 0 002.25-2.25V8.25L10.5 1.5z" />
                  </svg>
                </div>
                Create Room
              </h3>

              <form onSubmit={createRoom} className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-slate-300 mb-2">Room Name</label>
                  <input 
                    value={newRoom.roomId} 
                    onChange={(e) => setNewRoom((prev) => ({ ...prev, roomId: e.target.value }))} 
                    placeholder="e.g., 'Tournament #1'"
                    className="input-field" 
                    required 
                  />
                </div>

                <div className="grid grid-cols-2 gap-3">
                  <div>
                    <label className="block text-sm font-medium text-slate-300 mb-2">Max Players</label>
                    <input 
                      type="number" 
                      min={2} 
                      max={16}
                      value={newRoom.maxPlayers} 
                      onChange={(e) => setNewRoom((prev) => ({ ...prev, maxPlayers: e.target.value }))} 
                      className="input-field" 
                      required 
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-300 mb-2">Entry Fee (₹)</label>
                    <input 
                      type="number" 
                      min={1} 
                      value={newRoom.entryFee} 
                      onChange={(e) => setNewRoom((prev) => ({ ...prev, entryFee: e.target.value }))} 
                      className="input-field" 
                      required 
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-300 mb-2">Prize Distribution</label>
                  <select 
                    value={newRoom.prizeDistribution} 
                    onChange={(e) => setNewRoom((prev) => ({ ...prev, prizeDistribution: e.target.value }))}
                    className="select-field"
                  >
                    <option value="top4">Top 4 Get Prize</option>
                    <option value="winnerTA">Winner Takes All</option>
                  </select>
                </div>

                <button 
                  type="submit"
                  disabled={loading}
                  className="btn-secondary w-full disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  {loading ? 'Creating...' : 'Create Room'}
                </button>
              </form>
            </div>
          </div>

          {/* Available Contests Section */}
          <div className="lg:col-span-2">
            <h3 className="text-2xl font-bold mb-6 flex items-center">
              <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-sky-500 to-sky-600 flex items-center justify-center mr-3">
                <svg className="w-5 h-5 text-white" fill="currentColor" viewBox="0 0 20 20">
                  <path d="M6 2a1 1 0 011 1v2h6V3a1 1 0 112 0v2h4a2 2 0 012 2v10a2 2 0 01-2 2H4a2 2 0 01-2-2V7a2 2 0 012-2h4V3a1 1 0 011-1z" />
                </svg>
              </div>
              Available Contests
            </h3>

            {rooms.length === 0 ? (
              <div className="card text-center py-12">
                <svg className="w-16 h-16 mx-auto text-slate-600 mb-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 13V6a2 2 0 00-2-2H6a2 2 0 00-2 2v7m16 0v5a2 2 0 01-2 2H6a2 2 0 01-2-2v-5m16 0h-2.586a1 1 0 00-.707.293l-2.414 2.414a1 1 0 01-.707.293h-3.172a1 1 0 01-.707-.293l-2.414-2.414A1 1 0 006.586 13H4" />
                </svg>
                <p className="text-slate-400">No contests available yet</p>
                <p className="text-slate-500 text-sm mt-2">Be the first to create one!</p>
              </div>
            ) : (
              <div className="grid gap-4">
                {rooms.map((r) => (
                  <div key={r.roomId} className="card">
                    <div className="flex items-start justify-between mb-4">
                      <div>
                        <h4 className="text-lg font-bold text-white">{r.roomId}</h4>
                        <p className="text-slate-400 text-sm">
                          Prize: <span className="text-sky-400 font-semibold">
                            {r.prizeDistribution === 'top4' ? 'Top 4' : 'Winner Takes All'}
                          </span>
                        </p>
                      </div>
                      <div className={`px-3 py-1 rounded-full text-sm font-semibold ${
                        r.status === 'waiting' 
                          ? 'bg-green-900/50 text-green-400 border border-green-700' 
                          : r.status === 'active'
                          ? 'bg-blue-900/50 text-blue-400 border border-blue-700'
                          : 'bg-slate-700 text-slate-300 border border-slate-600'
                      }`}>
                        {r.status.charAt(0).toUpperCase() + r.status.slice(1)}
                      </div>
                    </div>

                    <div className="flex items-center justify-between mb-4">
                      <div className="flex gap-6">
                        <div>
                          <p className="text-slate-500 text-sm">Entry Fee</p>
                          <p className="text-white font-bold">₹{r.entryFee}</p>
                        </div>
                        <div>
                          <p className="text-slate-500 text-sm">Players</p>
                          <p className="text-white font-bold">{r.players.length}/{r.maxPlayers}</p>
                        </div>
                      </div>
                    </div>

                    <div className="flex gap-3">
                      <button 
                        disabled={r.status !== 'waiting' || loading}
                        onClick={() => joinRoom(r)}
                        className={`btn-primary btn-sm flex-1 disabled:opacity-50 disabled:cursor-not-allowed`}
                      >
                        {loading ? 'Joining...' : 'Join Now'}
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
